const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = d.runtime_mode || "MOCK";
d.correlation_id = d.correlation_id || ("KNG-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.user = d.user || {id:"system",name:"Auto",role:"user",department:"general"};
d.payload = d.payload || {};
d.metadata = d.metadata || {};
if (!d.payload.query && d.message) {
  d.payload.query = d.message;
}
const msg = (d.message || "").toLowerCase();
const q = (d.payload.query || "").toLowerCase();
if (!d.action) {
  if (d.payload.file_id || d.payload.file_name || d.payload.content) d.action = "sync_document";
  else if (d.payload.document_id && (/vigente|validar|vencido|check/.test(msg) || /vigente|validar|vencido|check/.test(q))) d.action = "verify_document";
  else if (d.payload.entity_type) d.action = "entity_memory";
  else if (/auditoria|\blog\b|rastrear|historico/.test(msg) || /auditoria|\blog\b|rastrear|historico/.test(q)) d.action = "audit_search";
  else if (/capa|plano de acao|corretiva|preventiva/.test(msg) || /capa|plano de acao|corretiva|preventiva/.test(q)) d.action = "capa_draft";
  else if (/nao conformidade|qualidade|falha/.test(msg) || /nao conformidade|qualidade|falha/.test(q)) d.action = "quality_check";
  else d.action = "query";
}
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "query";
const missing = [];
if (action === "query" && !pl.query && !d.message) {
  missing.push("query");
}
if (action === "sync_document" && !pl.file_name && !pl.content) {
  missing.push("file_name_or_content");
}
if (action === "verify_document" && !pl.document_id && !pl.file_name) {
  missing.push("document_id_or_file_name");
}
if (action === "entity_memory" && !pl.entity_type) {
  missing.push("entity_type");
}
d._validation = {valid: missing.length === 0, missing};
d._needs_info = missing.length > 0;
return [{json: d}];

const d = $input.first().json;
d._status = "needs_info";
const miss = (d._validation ? d._validation.missing : null) || ["query"];
d._clarification = {
  questions: miss.map(function(m){return "Informar " + m + " para consultar o RAG";}),
  missing: miss
};
return [{json: d}];

const d = $input.first().json;
const q = (d.payload.query || d.message || "").toLowerCase();
let type = "general";
if (/fornecedor|cotacao|compra|p2p/.test(q)) type = "purchase";
else if (/proposta|venda|cliente|quote|comercial/.test(q)) type = "commercial";
else if (/producao|kanban|\bop\b|ordem/.test(q)) type = "production";
else if (/computador|printer|impressora|email|rede|helpdesk|ticket/.test(q)) type = "internal_helpdesk";
else if (/nao conformidade|capa|auditoria|norma|inmetro|\bex\b|classificada/.test(q)) type = "quality";
else if (/lei|compliance|lgpd|regulamento/.test(q)) type = "compliance";
const isEx = /\bex\b|classificada|inmetro|explosao|seguranca/.test(q);
const isFin = /preco|valor|custo|margem|faturamento|financeiro/.test(q);
const isSec = /senha|token|credencial|acesso|permissao/.test(q);
const isQual = /qualidade|nao conformidade|capa|falha|norma/.test(q);
const sensitive = isEx || isFin || isSec || isQual || /cliente|fornecedor/.test(q);
d._classification = {
  query_type: type,
  requires_source: d.payload.require_sources !== false,
  sensitive: sensitive,
  ex_inmetro_related: isEx,
  financial_related: isFin,
  security_related: isSec,
  quality_related: isQual
};
return [{json: d}];

const d = $input.first().json;
const cls = d._classification || {};
const pl = d.payload || {};
const q = (pl.query || d.message || "").toLowerCase();
let risk = "low";
if (cls.security_related || cls.ex_inmetro_related || /creden|senha|token|chave|exaustor para area classificada/i.test(q)) {
  risk = "critical";
} else if (cls.financial_related || cls.quality_related || ["verify_document", "capa_draft"].includes(d.action) || /fornecedor|aco|compra|proposta|cliente|\bop\b|kanban/i.test(q)) {
  risk = "high";
} else if (["entity_memory", "audit_search", "sync_document"].includes(d.action) || /historico|rastrear|manual/i.test(q)) {
  risk = "medium";
}
d._risk_level = risk;
d._requires_approval = (risk === "critical" && ["verify_document", "capa_draft"].includes(d.action)) || (risk === "critical" && d.action === "query");
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const fname = pl.file_name || "documento_sem_nome.txt";
const docId = "doc_sync_" + Math.random().toString(36).substr(2,6);
const content = pl.content || "Conteudo mock do documento sincronizado.";
const chunks = [
  {chunk_id: docId + "_c1", text: content.substring(0, 100), offset: 0},
  {chunk_id: docId + "_c2", text: content.substring(100, 200), offset: 100}
].filter(function(c){return c.text.length > 0;});
d._sync_result = {
  document_id: docId,
  file_name: fname,
  chunks_created: chunks.length,
  chunks: chunks,
  embedding_status: "mocked",
  portal_synced: false,
  note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/knowledge/index" : "MOCK: chunks gerados"
};
d._status = "document_synced";
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const q = (pl.query || d.message || "").toLowerCase();
const docId = (pl.document_id || "").toLowerCase();
const fileName = (pl.file_name || "").toLowerCase();
if (d.runtime_mode === "PORTAL") {
  d._retrieved = {note: "TODO: POST /api/knowledge/query", sources: []};
  return [{json: d}];
}
const now = new Date();
const expired = new Date(now.getTime() - 30 * 86400000).toISOString().split("T")[0];
const future = new Date(now.getTime() + 180 * 86400000).toISOString().split("T")[0];
const db = [
  {
    source_id: "DOC-TECH-001",
    title: "Manual de Exaustores Axiais Vesper",
    document_type: "manual", module: "comercial", version: "2.1", status: "current",
    valid_until: future, owner: "Engenharia",
    snippet: "Os exaustores axiais Vesper devem ser instalados com distancia minima de 1.5 metros de obstaculos. Vazao nominal de 5000 m3/h.",
    tags: ["exaustor", "axial", "instalacao", "vazao"]
  },
  {
    source_id: "DOC-COMM-002",
    title: "Politica Comercial de Propostas e Margens",
    document_type: "politica", module: "comercial", version: "1.0", status: "current",
    valid_until: future, owner: "Comercial",
    snippet: "Margem minima para locacao de ventiladores e de 35% e para vendas e de 25%. Descontos adicionais requerem aprovacao da diretoria.",
    tags: ["margem", "desconto", "locacao", "venda", "politica"]
  },
  {
    source_id: "DOC-QUAL-003",
    title: "Procedimento de Cotacao de Fornecedores",
    document_type: "procedimento", module: "compras", version: "3.4", status: "current",
    valid_until: future, owner: "Compras",
    snippet: "Toda cotacao de fornecedor de aco deve conter no minimo 3 propostas validas. O prazo de entrega deve ser menor que 15 dias uteis.",
    tags: ["fornecedor", "cotacao", "compras", "aco", "prazo"]
  },
  {
    source_id: "DOC-SEC-004",
    title: "Documento Area EX e Certificacao INMETRO",
    document_type: "norma", module: "quality", version: "1.2", status: "current",
    valid_until: future, owner: "Qualidade",
    snippet: "Equipamentos para area classificada EX zona 1 requerem certificacao INMETRO and selo de conformidade ativo antes da expedicao.",
    tags: ["ex", "inmetro", "classificada", "explosao", "qualidade", "selo"]
  },
  {
    source_id: "DOC-QUAL-VENCIDO",
    title: "Procedimento de Qualidade Antigo",
    document_type: "procedimento", module: "quality", version: "1.0", status: "outdated",
    valid_until: expired, owner: "Qualidade",
    snippet: "Procedimento antigo de inspecao visual de solda antes da auditoria de 2024.",
    tags: ["qualidade", "inspecao", "solda", "vencido"]
  },
  {
    source_id: "MEM-SUPP-001",
    title: "Historico do Fornecedor Aco Rio",
    document_type: "historico", module: "compras", version: "1.0", status: "current",
    valid_until: future, owner: "Compras",
    snippet: "Aco Rio possui score de 92%. Prazo medio de entrega e de 12 dias. Historico de boa qualidade sem nao conformidades recentes.",
    tags: ["aco rio", "fornecedor", "score", "entrega"]
  },
  {
    source_id: "MEM-MAT-002",
    title: "Historico da Chapa Galvanizada 0.80",
    document_type: "historico", module: "general", version: "1.0", status: "current",
    valid_until: future, owner: "Compras",
    snippet: "Chapa galvanizada 0.80 mm ultimo preco registrado foi R$ 45.00/m2 com o fornecedor Aco Rio em marco de 2026.",
    tags: ["chapa", "galvanizada", "preco", "aco rio"]
  }
];
const matched = db.filter(function(doc) {
  if (docId && doc.source_id.toLowerCase() === docId) return true;
  if (fileName && doc.title.toLowerCase().indexOf(fileName) !== -1) return true;
  if (!q) return false;
  const words = q.split(/\s+/).filter(function(w){return w.length > 2;});
  let score = 0;
  words.forEach(function(w) {
    if (doc.title.toLowerCase().indexOf(w) !== -1) score += 3;
    if (doc.snippet.toLowerCase().indexOf(w) !== -1) score += 2;
    doc.tags.forEach(function(t){
      if (t.toLowerCase().indexOf(w) !== -1) score += 1;
    });
  });
  return score > 0;
});
const top_k = pl.top_k || 5;
d._retrieved = {
  sources: matched.slice(0, top_k),
  total_found: matched.length
};
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const sources = (d._retrieved && d._retrieved.sources) || [];
let status = "success";
let docInfo = {};
if (sources.length > 0) {
  const first = sources[0];
  docInfo = {
    document_id: first.source_id,
    title: first.title,
    status: first.status,
    valid_until: first.valid_until,
    version: first.version,
    owner: first.owner,
    is_expired: new Date(first.valid_until) < new Date()
  };
  if (first.status === "outdated" || docInfo.is_expired) {
    status = "document_outdated";
    d._risk_level = "high";
  }
} else {
  status = "failed";
  docInfo = {document_id: pl.document_id, status: "unknown", note: "Documento nao encontrado na base."};
}
d._verification_result = docInfo;
d._status = status;
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const type = pl.entity_type || "other";
const id = pl.entity_id || "unknown";
let memory = {};
if (d.runtime_mode === "PORTAL") {
  memory = {note: "TODO: GET /api/knowledge/entity-memory?type=" + type + "&id=" + id};
} else {
  if (type === "supplier") {
    memory = {
      entity_id: id,
      entity_type: type,
      supplier_name: "Aco Rio LTDA",
      quality_score: 0.92,
      average_delivery_days: 12,
      last_quotes: ["RFQ-102", "RFQ-105"],
      risk_notes: "Sem nao conformidades nos ultimos 12 meses."
    };
  } else if (type === "material") {
    memory = {
      entity_id: id,
      entity_type: type,
      material_name: "Chapa Galvanizada 0.80 mm",
      last_price: 45.00,
      price_unit: "m2",
      suppliers: ["Aco Rio", "Metalurgica Sul"],
      sku_candidates: ["SKU-GALV-080"]
    };
  } else {
    memory = {
      entity_id: id,
      entity_type: type,
      note: "MOCK: memoria generica de entidade",
      last_updated: new Date().toISOString()
    };
  }
}
d._entity_memory = memory;
d._status = "success";
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const cid = d.correlation_id;
d._audit_result = {
  correlation_id: cid,
  query_id: d.request_id,
  events: [
    {timestamp: new Date(Date.now() - 5000).toISOString(), event_type: "interno.request_received", user: d.user.id},
    {timestamp: new Date().toISOString(), event_type: "knowledge.query_received", user: "system"}
  ],
  total_events: 2,
  note: d.runtime_mode === "PORTAL" ? "TODO: GET /api/auditoria/by-correlation/" + cid : "MOCK: logs recuperados"
};
d._status = "audit_ready";
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const sources = (d._retrieved && d._retrieved.sources) || [];
let issues = [];
let status = "success";
if (sources.length > 0) {
  const first = sources[0];
  if (first.status === "outdated") {
    issues.push("Documento de referencia '" + first.title + "' esta vencido/outdated");
    status = "quality_review_required";
  }
} else {
  issues.push("Nenhuma fonte documental homologada encontrada para validar a acao.");
  status = "quality_review_required";
}
d._quality_result = {
  quality_status: issues.length === 0 ? "ok" : "review_required",
  issues: issues,
  checked_at: new Date().toISOString(),
  recommended_action: issues.length === 0 ? "Prosseguir operacionalmente" : "Acionar departamento de qualidade para revisao da norma."
};
d._status = status;
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
d._capa_result = {
  capa_id: "CAPA-DRAFT-" + Math.random().toString(36).substr(2,6).toUpperCase(),
  problem: d.message || pl.notes || "Nao conformidade identificada no fluxo de qualidade.",
  probable_cause: "Uso de procedimentos desatualizados ou falta de treinamento na equipe.",
  containment: "Bloquear movimentacao do lote / suspender uso da versao do documento.",
  corrective_action: "Atualizar documento para a versao homologada e registrar no Portal.",
  preventive_action: "Criar alerta automatico de 15 dias antes do vencimento no modulo de auditoria.",
  suggested_owner: "TI / Qualidade",
  suggested_deadline: new Date(Date.now() + 15 * 86400000).toISOString().split("T")[0],
  status: "draft",
  requires_approval: true,
  note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/qualidade/capa" : "MOCK: rascunho de CAPA gerado"
};
d._status = "capa_draft_ready";
d._requires_approval = true;
return [{json: d}];

const d = $input.first().json;
const sources = (d._retrieved && d._retrieved.sources) || [];
const strict = d.payload.strict_mode !== false;
let answer = "";
let status = "sources_found";
let conf = 0;
if (sources.length === 0) {
  answer = "Nao encontrei fonte confiavel suficiente para responder com seguranca.";
  status = "no_sources";
  conf = 0;
} else {
  const first = sources[0];
  conf = first.status === "current" ? 0.90 : 0.40;
  if (first.source_id === "DOC-SEC-004") {
    answer = "De acordo com o documento '" + first.title + "' (v" + first.version + "), " + first.snippet;
  } else if (first.source_id === "DOC-QUAL-003") {
    answer = "De acordo com a diretriz '" + first.title + "', toda cotacao de aco precisa de 3 propostas validas com entrega < 15 dias.";
  } else {
    answer = "Baseado em '" + first.title + "': " + first.snippet;
  }
}
d._answer_data = {
  answer: answer,
  sources: sources,
  confidence: conf,
  gaps: sources.length === 0 ? ["fontes_insuficientes"] : [],
  strict_mode: strict
};
d._status = status;
return [{json: d}];

const d = $input.first().json;
const evtMap = {
  "query":"knowledge.query_received", "sync_document":"knowledge.document_synced",
  "verify_document":"knowledge.document_verified", "entity_memory":"knowledge.entity_memory_queried",
  "audit_search":"knowledge.audit_search_ready", "quality_check":"quality.review_required",
  "capa_draft":"quality.capa_draft_created"
};
d._audit = {
  event_type: evtMap[d.action] || "knowledge.processed",
  correlation_id: d.correlation_id, request_id: d.request_id,
  action: d.action, status: d._status, risk_level: d._risk_level || "low",
  runtime_mode: d.runtime_mode, timestamp: new Date().toISOString(),
  note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/automation/audit" : "MOCK: audit_logged=true"
};
return [{json: d}];

const d = $input.first().json;
d._error_note = "TODO: vincular LpsYX0AkHTdZKw7P nas Settings";
d._status = "failed";
return [{json: d}];

function generateId() { return Math.random().toString(36).substr(2, 9); }

const raw = $input.first().json;
const body = raw.body || raw;

const input = {
  runtime_mode: body.runtime_mode || $env.VESPER_RUNTIME_MODE || "MOCK",
  correlation_id: body.correlation_id || "gw_" + generateId(),
  request_id: body.request_id || "req_" + generateId(),
  source: body.source || "manual",
  user: body.user || { id: "", name: "", role: "", department: "" },
  module_hint: body.module_hint || "",
  message: body.message || body.payload?.description || "",
  payload: body.payload || {},
  approved: body.approved || false,
  metadata: body.metadata || {}
};

return [{ json: input }];

const d = $input.first().json;
let valid = true;
const missing = [];

if (!d.message && (!d.payload || Object.keys(d.payload).length === 0)) {
  valid = false;
  missing.push("message or payload required");
}

if (!d.user?.id && d.runtime_mode === "PORTAL") {
  missing.push("user.id recommended for PORTAL mode");
}

d._validation = { valid, missing };
if (!valid) d._needs_info = true;

return [{ json: d }];

const d = $input.first().json;

if (d.runtime_mode === "PORTAL" && d.user?.id) {
  d._permissions = { _placeholder: true, note: "PORTAL will call GET /api/users/{id}/permissions" };
} else {
  d._permissions = {
    granted: ["compras.read","compras.create","propostas.read","kanban.read","helpdesk.create","ia.use"]
  };
}

return [{ json: d }];

const d = $input.first().json;
const text = (d.message + " " + JSON.stringify(d.payload)).toLowerCase();
const hint = (d.module_hint || "").toLowerCase();

const kw = {
  compras: ["comprar","compra","cotação","cotacao","fornecedor","pedido de compra","orçamento fornecedor","chapa","material","nfe","nota fiscal","preço fornecedor"],
  comercial_propostas: ["proposta","orçamento cliente","cliente pediu","cotar para cliente","venda","locação","locacao","exaustor","ventilador","climatizador","ventfog","pdf proposta"],
  producao_kanban: ["op ","produção","producao","kanban","card","checklist","prazo","atrasado","material pendente","fábrica","fabrica"],
  interno_geral: ["helpdesk","chamado","pc","computador","senha","acesso","certificado","usuário","usuario","chat interno","ti","impressora","rede"],
  knowledge_query: ["manual","procedimento","norma","documento","histórico","historico","política","politica","como funciona","consultar"],
  approval: ["aprovar","aprovação","aprovacao","rejeitar","aprovado","rejected","approved","approval_id","appr_"],
  audit_error: ["erro","falha","exception","dead letter","auditoria","workflow falhou"]
};

let intent = "unknown";
let confidence = 0.30;

// Prioridade: module_hint
if (hint && kw[hint]) {
  const hit = kw[hint].some(k => text.includes(k));
  intent = hint;
  confidence = hit ? 0.95 : 0.80;
} else {
  let best_intent = "unknown";
  let max_hits = 0;
  for (const [k, words] of Object.entries(kw)) {
    const hits = words.filter(w => text.includes(w)).length;
    if (hits > max_hits) {
      max_hits = hits;
      best_intent = k;
    } else if (hits === max_hits && max_hits > 0) {
      if (k === "approval" || k === "audit_error") {
        best_intent = k;
      }
    }
  }
  if (max_hits >= 2) {
    intent = best_intent;
    confidence = 0.85;
  } else if (max_hits === 1) {
    intent = best_intent;
    confidence = 0.60;
  }
}

// Entity extraction
const entities = {};
const amtMatch = text.match(/r\$\s?([\d.,]+)/);
if (amtMatch) {
  let val = amtMatch[1].replace(/\./g, "").replace(",", ".");
  entities.amount = parseFloat(val) || 0;
} else {
  entities.amount = 0;
}
const opMatch = text.match(/ op[\s_]?(\d+)/i);
if (opMatch) entities.op_id = opMatch[0];
const apprMatch = text.match(/appr_\w+/);
if (apprMatch) entities.approval_id = apprMatch[0];
entities.customer_related = /cliente|proposta/.test(text);
entities.supplier_related = /fornecedor|cotação|cotacao/.test(text);
entities.financial_related = /compra|preço|r\$|orçamento|proposta/.test(text);
entities.production_related = / op |produção|kanban/.test(text);
entities.security_related = /senha|acesso|token|credencial/.test(text);
entities.ex_inmetro_related = / ex |área classificada|inmetro|explosão|prova de explosão/.test(text);

// Risk
let risk = "low";
if (entities.financial_related || entities.customer_related || entities.supplier_related || entities.security_related) risk = "high";
if (entities.production_related && !entities.financial_related) risk = "medium";
if (intent === "knowledge_query") risk = "low";
if (entities.ex_inmetro_related) risk = "critical";
if (intent === "audit_error") risk = "medium";

d._intent = intent;
d._confidence = confidence;
d._entities = entities;
d._risk_level = risk;

return [{ json: d }];

const d = $input.first().json;
const text = (d.message + " " + JSON.stringify(d.payload)).toLowerCase();

let requires_approval = false;
let status = "routed";

if (d._needs_info || (d._intent === "unknown" && d._confidence < 0.70)) {
  status = "needs_info";
}

// Ações sensíveis/finais que o Gateway bloqueia diretamente
const isFinalAction = 
  /enviar\s+(proposta|pedido|compra)/.test(text) ||
  /resetar\s+senha/.test(text) ||
  /alterar\s+acesso/.test(text) ||
  /excluir|deletar/.test(text) ||
  /mover\s+.*crítico/.test(text) ||
  /data\s+deletion/.test(text) ||
  (d._entities?.ex_inmetro_related && /enviar|aprovar|finalizar|emitir/.test(text));

if (isFinalAction && !d.approved) {
  requires_approval = true;
  status = "approval_pending";
}

let approval_id = null;
if (requires_approval) {
  approval_id = d._entities?.approval_id || ("appr_gw_" + Math.random().toString(36).substr(2,8));
}

d._policy = { requires_approval, status, approval_id };

return [{ json: d }];

const d = $input.first().json;
const out = {
  runtime_mode: d.runtime_mode,
  correlation_id: d.correlation_id,
