const d = $input.first().json;
let body = d.payload?.body || d.message || "";
body = body.replace(/^>.*$/gm,"").replace(/_{10,}/g,"").replace(/De:.*\nEnviado:.*\nPara:.*/gm,"");
body = body.replace(/\n{3,}/g,"\n\n").trim();
d._cleaned_body = body;
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "intake";
const body = d._cleaned_body || d.message || "";
if(["generate_pdf","send_proposal","schedule_followup","win_loss","request_approval"].includes(action)){
  d._validation={valid:true,missing:[]};d._needs_info=false;return [{json:d}];
}
const missing = [];
const hasCustomer = pl.customer?.company_name||pl.customer?.email||pl.from;
const hasProduct = pl.requested_products?.length||pl.requested_service||body.length>20;
if(!hasCustomer) missing.push("customer");
if(!hasProduct) missing.push("requested_products");
d._validation={valid:missing.length===0,missing};
d._needs_info=missing.length>0;
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const text = (d._cleaned_body||d.message||pl.body||"").toLowerCase();
const sub = (pl.subject||"").toLowerCase();
const full = text + " " + sub;
const cust = pl.customer || {};
const exInmetro = /\\bex\\b|area classificada|inmetro|zona explosiva|a prova de explos/.test(full);
const competitor = /outra empresa|concorrente|mais barato|recebi proposta|cotação de outra/.test(full);
let category = "geral";
if(/exaustor/.test(full)) category="exaustor";
else if(/ventilador|ventfog/.test(full)) category="ventilador";
else if(/climatizador|climatiza/.test(full)) category="climatizacao";
else if(/cortina de ar/.test(full)) category="cortina_ar";
else if(/micro.?ventilador/.test(full)) category="microventilador";
let proposal_type = "venda";
if(/loca.{0,5}o|aluguel/.test(full)) proposal_type="locacao";
else if(/manuten.{0,5}o|conserto|reparo/.test(full)) proposal_type="manutencao";
else if(/servi.{0,5}o/.test(full)) proposal_type="servico";
const qtyM = full.match(/(\\d+)\\s*(unidade|un|pe.a|equipamento)/);
d._customer = {
  company_name: cust.company_name || pl.from?.split("@")[0] || "Nao identificado",
  email: cust.email || pl.from || "",
  contact_name: cust.contact_name || "",
  phone: cust.phone || "",
  cnpj: cust.cnpj || "",
  address: cust.address || ""
};
d._demand = {
  requested_products: pl.requested_products || [category],
  product_category: category,
  proposal_type,
  quantity: pl.quantity || (qtyM?qtyM[1]:"1"),
  deadline: pl.deadline || "",
  technical_specs: pl.technical_specs || "",
  budget: pl.budget || 0,
  urgency: /urgent|urgente|r.pido/.test(full)?"alta":"normal",
  ex_inmetro_related: exInmetro,
  competitor_mentioned: competitor,
  image_analysis_required: false,
  pdf_analysis_required: (pl.attachments||[]).length>0
};
return [{json:d}];

const d = $input.first().json;
const email = d._customer?.email || "";
const company = d._customer?.company_name || "";
d._customer_lookup = d.runtime_mode==="PORTAL" ? {
  note:"TODO: GET /api/clientes/search?query="+encodeURIComponent(company),
  customer_id: null, customer_status:"unknown"
} : {
  customer_id: "CUST-MOCK-" + Math.random().toString(36).substr(2,6).toUpperCase(),
  customer_status: email.includes("@") ? "existing" : "new",
  last_proposal_date: "2025-01-15",
  commercial_owner: "Vendedor Vesper",
  risk_notes: []
};
d._customer.id = d._customer_lookup.customer_id;
return [{json:d}];

const d = $input.first().json;
const dem = d._demand || {};
const cat = dem.product_category || "geral";
const pt = dem.proposal_type || "venda";
const ex = dem.ex_inmetro_related;
let tid = "TEMPLATE-GERAL", tname = "Proposta Geral", reason = "padrao";
if(ex){tid="TEMPLATE-AREA-EX-INMETRO";tname="Proposta Area EX/INMETRO";reason="ex_inmetro_detectado";}
else if(cat==="exaustor"){tid="TEMPLATE-EXAUSTOR-AXIAL";tname="Proposta Exaustor Axial";}
else if(cat==="ventilador"){tid="TEMPLATE-VENTILADOR-INDUSTRIAL";tname="Proposta Ventilador Industrial";}
else if(cat==="climatizacao"){tid="TEMPLATE-CLIMATIZACAO";tname="Proposta Climatizacao";}
else if(pt==="locacao"){tid="TEMPLATE-LOCACAO-EQUIPAMENTOS";tname="Proposta Locacao";}
else if(pt==="manutencao"){tid="TEMPLATE-MANUTENCAO";tname="Proposta Manutencao";}
d._template = {template_id:tid,template_name:tname,template_confidence:ex?0.99:0.85,template_reason:reason};
return [{json:d}];

const d = $input.first().json;
const dem = d._demand || {};
const lk = d._customer_lookup || {};
let risk = "low";
if(dem.ex_inmetro_related) risk="critical";
else if(dem.competitor_mentioned||dem.budget>0||(lk.customer_status==="new")) risk="high";
else if(dem.product_category!=="geral") risk="medium";
d._risk_level = risk;
d._requires_approval = ["high","critical"].includes(risk);
d._policy = {
  requires_approval: ["high","critical"].includes(risk),
  technical_review: dem.ex_inmetro_related===true,
  send_blocked: true,
  discount_blocked: true,
  reason: dem.ex_inmetro_related?"EX/INMETRO - revisao obrigatoria":dem.competitor_mentioned?"Concorrente detectado":"padrao"
};
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const cust = d._customer || {};
const dem = d._demand || {};
const tpl = d._template || {};
const pid = d.runtime_mode==="PORTAL" ? "prop_portal_pending" :
  "prop_mock_"+Math.random().toString(36).substr(2,8);
d._proposal = {
  proposal_id: pl.proposal_id || pid,
  title: `Proposta ${tpl.template_name||"Geral"} - ${cust.company_name||"Cliente"}`,
  status: "draft",
  customer: cust,
  demand: dem,
  template_id: tpl.template_id,
  missing_technical: dem.ex_inmetro_related?["certificacao_ex","tensao","potencia","norma_aplicavel"]:[],
  clarification_needed: d._validation?.missing||[],
  draft_body: `Prezado(a) ${cust.contact_name||"Cliente"},\n\nAgradecemos o contato.\n[RASCUNHO - Completar com especificacoes tecnicas]\n\nCorr: ${d.correlation_id}`,
  portal_synced: false,
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/propostas/drafts":"MOCK: draft simulado",
  created_at: new Date().toISOString()
};
d._status = d._demand?.ex_inmetro_related ? "technical_review_required" :
  (d._requires_approval ? "approval_pending" : "draft_created");
return [{json:d}];

const d = $input.first().json;
if (!d._requires_approval && d._status === "draft_created") {
  return [{json:d}];
}
const pl = d.payload || {};
const atype = d._demand?.ex_inmetro_related?"ex_area_validation":"proposal_send";
const aid = pl.approval_id || ("appr_comercial_"+Math.random().toString(36).substr(2,8));
d._approval_id = aid;
d._approval_payload = {
  runtime_mode: d.runtime_mode,
  correlation_id: d.correlation_id,
  approval_type: atype,
  requested_by: d.user,
  summary: "Aprovar proposta para: " + (d._customer?.company_name||"cliente"),
  details: {customer:d._customer,proposal:d._proposal,template:d._template,risk_notes:d._policy?.reason||""},
  risk_level: d._risk_level,
  amount: d._demand?.budget||0,
  currency: "BRL"
};
d._status = "approval_pending";
const note = d.runtime_mode==="PORTAL"?
  "TODO: Execute Workflow aY5nyRrZ3ugYT6ZH ou POST /webhook/vesper/core/approval/request":
  "MOCK: approval_id="+aid;
d._approval_note = note;
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
if(!pl.approved && !pl.approval_id){
  d._status="approval_pending";
  d._blocked_reason="PDF final requer aprovacao previa";
  return [{json:d}];
}
const pdf_id = d.runtime_mode==="PORTAL"?"pdf_portal_pending":
  "pdf_mock_"+Math.random().toString(36).substr(2,8);
d._pdf = {
  pdf_id, pdf_url: d.runtime_mode==="PORTAL"?
    "TODO: GET /api/propostas/"+d._proposal?.proposal_id+"/pdf":
    "http://mock.vesper.local/pdf/"+pdf_id+".pdf",
  generated_at: new Date().toISOString(),
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/propostas/{id}/generate-pdf":"MOCK: pdf simulado"
};
d._status="pdf_ready";
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
if(!pl.approved && !pl.approval_id){
  d._status="approval_pending";
  d._blocked_reason="Envio de proposta requer aprovacao";
  return [{json:d}];
}
d._send_result = {
  status:"sent_placeholder",
  note:"NUNCA enviar email real nesta v1 - " +
    (d.runtime_mode==="PORTAL"?"TODO: POST /api/propostas/{id}/send":"MOCK: sent=true"),
  email_disabled: true,
  sent_at: new Date().toISOString()
};
d._status="sent_placeholder";
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const days = d._demand?.urgency==="alta"?1:d._demand?.ex_inmetro_related?3:2;
d._followup = {
  followup_id: "fu_mock_"+Math.random().toString(36).substr(2,8),
  proposal_id: pl.proposal_id||d._proposal?.proposal_id||"",
  scheduled_days: days,
  scheduled_date: new Date(Date.now()+days*86400000).toISOString().split("T")[0],
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/propostas/{id}/followup":"MOCK: followup agendado"
};
d._status="followup_scheduled";
return [{json:d}];

const d = $input.first().json;
if(d._demand?.ex_inmetro_related && !["technical_review_required","approval_pending"].includes(d._status)){
  d._risk_level="critical";d._requires_approval=true;
  if(d._status==="draft_created") d._status="technical_review_required";
}
if(d._demand?.competitor_mentioned && d._risk_level==="low") d._risk_level="high";
const evtMap = {
  "intake":"comercial.intake_received","email_intake":"comercial.intake_received",
  "create_draft":"comercial.draft_created","technical_review":"comercial.technical_review_required",
  "request_approval":"comercial.approval_requested","generate_pdf":"comercial.pdf_ready",
  "send_proposal":"comercial.proposal_send_placeholder","schedule_followup":"comercial.followup_scheduled"
};
d._audit = {
  event_type: evtMap[d.action]||"comercial.processed",
  correlation_id: d.correlation_id, request_id: d.request_id,
  action: d.action, status: d._status,
  customer: d._customer||{}, risk_level: d._risk_level||"low",
  runtime_mode: d.runtime_mode, timestamp: new Date().toISOString(),
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/automation/audit":"MOCK: audit_logged=true"
};
return [{json:d}];

const d = $input.first().json;
d._status="needs_info";
const qs = [];
const miss = d._validation?.missing||[];
if(miss.includes("customer")) qs.push("Qual a empresa/cliente e e-mail para contato?");
if(miss.includes("requested_products")) qs.push("Qual produto ou servico esta buscando?");
d._clarification_questions = qs;
d._clarification_draft = "Prezado cliente,\n\nPara darmos continuidade, precisamos de:\n"+qs.map(q=>"- "+q).join("\n")+"\n\nAguardamos retorno.\nEquipe Vesper";
return [{json:d}];
